import { Registry } from "../../core/zc-registry";

const geoPin1 = (size) => {
    return {
        outer:
            `${'M' + ' '}${size * 0.2167} ${size * -0.7833}C` +
            ` ${size * 0.2167} ${size * -0.9033} ${size * 0.12} ${size * -1} ${0} ${size * -1}S` +
            ` ${size * -0.2167} ${size * -0.9033} ${size * -0.2167} ${size * -0.7833}C` +
            ` ${size * -0.2167} ${size * -0.67} ${size * -0.1267} ${size * -0.5767} ${size * -0.0167} ${size * -0.5667}L` +
            ` ${size * -0.0167} ${size * -0.0167}C` +
            ` ${size * -0.0167} ${size * -0.0067} ${size * -0.01} ${0} ${0} ${0}S` +
            ` ${size * 0.0167} ${size * -0.0067} ${size * 0.0167} ${size * -0.0167}L` +
            ` ${size * 0.0167} ${size * -0.5667}C` +
            ` ${size * 0.1267} ${size * -0.5767} ${size * 0.2167} ${size * -0.67} ${size * 0.2167} ${size * -0.7833}z`,
        inner:
            `${'M' + ' '}${0} ${size * -1.8}C` +
            ` ${size * -0.1267} ${size * -1.8} ${size * -0.2333} ${size * -1.6933} ${size * -0.2333} ${size * -1.5667}C` +
            ` ${size * -0.2333} ${size * -1.5467} ${size * -0.2467} ${size * -1.5333} ${size * -0.2667} ${size * -1.5333}S` +
            ` ${size * -0.3} ${size * -1.5467} ${size * -0.3} ${size * -1.5667}C` +
            ` ${size * -0.3} ${size * -1.7333} ${size * -0.1667} ${size * -1.8667} ${0} ${size * -1.8667}C` +
            ` ${size * 0.02} ${size * -1.8667} ${size * 0.0333} ${size * -1.8533} ${size * 0.0333} ${size * -1.8333}S` +
            ` ${size * 0.02} ${size * -1.8} ${0} ${size * -1.8}z`
    }
};
Registry.getComponent('svg.symbols.constants')['geo-pin-1'] = geoPin1;
export default geoPin1;